export async function seedThoughtLeadershipArticles(): Promise<void> {
  try {
    for (const article of SEED_ARTICLES) {
      const existing = await db.select({ id: thoughtLeadershipArticles.id })
        .from(thoughtLeadershipArticles)
        .where(eq(thoughtLeadershipArticles.slug, article.slug))
        .limit(1);

      if (existing.length === 0) {
        await db.insert(thoughtLeadershipArticles).values({
          ...article,
          publishedAt: new Date(),
          createdAt: new Date(),
          updatedAt: new Date(),
        });
        logInfo(`Seeded article: ${article.title}`);
      }
    }
  } catch (error) {
    logInfo(`Article seed skipped (table may not exist yet): ${error instanceof Error ? error.message : String(error)}`);
  }
}
